    LedDriver(led_driver_handle_t handle) : handle_(handle) {}

    esp_err_t setPower(bool power) {
        // Use safer function to copy string
        char powerStr[10];
        strlcpy(powerStr, power ? "true" : "false", sizeof(powerStr));
        return led_driver_set_power(handle_, powerStr);
    }

private:
    led_driver_handle_t handle_;
